import{_ as a,c as e,o as t,a1 as s}from"./chunks/framework.BtBsNfS7.js";const g=JSON.parse('{"title":"NapCatQQ","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/guide/getting-started.md","filePath":"en-US/guide/getting-started.md","lastUpdated":1718559514000}'),o={name:"en-US/guide/getting-started.md"},i=s(`<h1 id="napcatqq" tabindex="-1">NapCatQQ <a class="header-anchor" href="#napcatqq" aria-label="Permalink to &quot;NapCatQQ&quot;">​</a></h1><p>NapCatQQ is a QQ Bot framework based on the PC NTQQ client body, which is stable, secure, and quickly deployable.</p><h2 id="advantages-of-napcatqq" tabindex="-1">Advantages of NapCatQQ <a class="header-anchor" href="#advantages-of-napcatqq" aria-label="Permalink to &quot;Advantages of NapCatQQ&quot;">​</a></h2><ul><li><p>No need for a graphical environment, performs well on Linux, and has a fundamental difference from existing Hook frameworks, far superior in performance and memory usage.</p></li><li><p>Simple configuration, supports remote browser access for configuration, easy and simple to complete.</p></li><li><p>Rapid adaptation to NTQQ functions, continuous updates to follow the latest version of QQ.</p></li></ul><h2 id="things-to-know-before-starting-read-three-times" tabindex="-1">Things to Know Before Starting (Read Three Times!) <a class="header-anchor" href="#things-to-know-before-starting-read-three-times" aria-label="Permalink to &quot;Things to Know Before Starting (Read Three Times!)&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li><p>NapCat is a QQ Bot framework based on the PC NTQQ client body, so you need to install the <strong>QQ version corresponding to NapCatQQ</strong> in advance to run NapCat.</p></li><li><p>When NapCat is online, you cannot achieve human-computer unity using the PC QQ client, but you can choose to log in synchronously on the mobile client. If you want human-computer unity on PC, please use <a href="https://github.com/LLOneBot/LLOneBot" target="_blank" rel="noreferrer">LLOneBot</a>.</p></li><li><p>NapCat is different from protocol implementation; it is based on the QQ client. Things that cannot be done on the QQ client, NapCat &gt;_&lt; can&#39;t do it either!</p></li></ul></div><h2 id="install-qq" tabindex="-1">Install QQ <a class="header-anchor" href="#install-qq" aria-label="Permalink to &quot;Install QQ&quot;">​</a></h2><p>NapCatQQ v1.4.7:</p><p><a href="https://dldir1.qq.com/qqfile/qq/QQNT/Windows/QQ_9.9.10_240523_x64_01.exe" target="_blank" rel="noreferrer">Windows 9.9.10-24108</a> | <a href="https://dldir1.qq.com/qqfile/qq/QQNT/8b4fdf81/linuxqq_3.2.7-23361_amd64.deb" target="_blank" rel="noreferrer">Linux 3.2.7-23361</a></p><p>Linux does not need a desktop to install NTQQ. The specific command is as follows:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libgbm1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libasound2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./qq.deb</span></span></code></pre></div><p>For more versions, please refer to <a href="./version">Version Update Log</a>.</p><h2 id="download-napcatqq" tabindex="-1">Download NapCatQQ <a class="header-anchor" href="#download-napcatqq" aria-label="Permalink to &quot;Download NapCatQQ&quot;">​</a></h2><p>Download link: <a href="https://github.com/NapNeko/NapCatQQ/releases" target="_blank" rel="noreferrer">https://github.com/NapNeko/NapCatQQ/releases</a></p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>To avoid secondary startup, you can pre-configure the basic settings of NapCat, see <a href="./config">Configure NapCat</a>.</p><h2 id="startup" tabindex="-1">Startup <a class="header-anchor" href="#startup" aria-label="Permalink to &quot;Startup&quot;">​</a></h2><details class="details custom-block"><summary>Windows</summary><p>After installing the corresponding version of QQ, in most cases, you only need to unzip NapCat and place it anywhere you want. But be careful, the path cannot contain spaces. Then, double-click <code>napcat.bat</code> to run!</p><p>Wait! If you encounter garbled characters, you can try double-clicking <code>napcat-utf8.bat</code> to start.</p><p>If the above method still does not work, you can try to start with PowerShell:</p><p>Start PowerShell, run <code>powershell ./napcat.ps1</code> or <code>napcat.bat</code>, if garbled characters appear, you can try to run <code>napcat-utf8.ps1</code> or <code>napcat-utf8.bat</code>.</p><p>If it still doesn&#39;t work, you can try <code>powershell.exe -ExecutionPolicy Bypass -File &quot;.\\napcat.ps1&quot;</code>.</p><p><strong>It is recommended to directly click the bat to run, because PowerShell itself will occupy about 20 MB of memory.</strong></p></details><details class="details custom-block"><summary>Linux One-Click Script</summary><p>Highly recommended!</p><p><code>curl -o napcat.sh https://fastly.jsdelivr.net/gh/NapNeko/NapCat-Installer@master/script/install.sh &amp;&amp; sudo bash napcat.sh</code></p></details><details class="details custom-block"><summary><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">Linux Docker</a></summary></details><details class="details custom-block"><summary>Linux Non-Docker</summary><p>Run in the terminal</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u+x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./napcat.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./napcat.sh</span></span></code></pre></div><p>Do not start with <code>sh napcat.sh</code>, as it may cause path problems and fail to start.</p></details><details class="details custom-block"><summary><a href="https://github.com/NapNeko/NapCat-Termux" target="_blank" rel="noreferrer">Android Termux</a></summary></details><details class="details custom-block"><summary>Quick Login (No Need to Scan)</summary><p>If you have successfully logged in to the official QQ or NapCatQQ, you can add the parameter <code>-q &lt;Your QQ&gt;</code> for quick login without scanning. For example, <code>napcat.bat -q 1234567</code> or <code>napcat.sh -q 1234567</code>.</p></details><h3 id="after-startup" tabindex="-1">After Startup <a class="header-anchor" href="#after-startup" aria-label="Permalink to &quot;After Startup&quot;">​</a></h3><p>Congratulations, if you see this, you have successfully started NapCat, you can try reading the advanced instructions below!</p><p><a href="/zh-CN/guide/config">How to Configure NapCat&#39;s Basic Settings</a></p><p><a href="/zh-CN/guide/faq">How to Configure NapCat&#39;s Voice Sending</a> Refer to the entry <code>Voice/Video Sending Failed</code></p><p><a href="/zh-CN/guide/faq">How to Solve NapCat Crash Issues</a></p>`,28),n=[i];function r(l,p,c,d,h,u){return t(),e("div",null,n)}const f=a(o,[["render",r]]);export{g as __pageData,f as default};
